tool_response:
"""Discovery + apply for Prefect deployments declared by formula packs.

Packs register a `register()` callable under the `po.deployments` entry-point
group. The callable returns one `RunnerDeployment` (built via
`flow.to_deployment(...)`) or a list of them. Core stays flow-agnostic.

    # pack pyproject.toml
    [project.entry-points."po.deployments"]
    software-dev = "po_formulas.deployments:register"

    # pack module
    def register():
        return [epic_run.to_deployment(name="nightly", schedule=Cron("0 9 * * *"))]
"""

from __future__ import annotations

import logging
import os
import tomllib
from dataclasses import dataclass
from importlib.metadata import entry_points
from pathlib import Path
from typing import Any

logger = logging.getLogger(__name__)


@dataclass
class LoadedDeployment:
    """Pairs a deployment with the pack name (EP name) that produced it."""

    pack: str
    deployment: Any  # prefect.deployments.runner.RunnerDeployment


@dataclass
class LoadError:
    pack: str
    error: str


def _iter_group_entry_points(group: str) -> list[Any]:
    try:
        return list(entry_points(group=group))
    except TypeError:
        return list(entry_points().get(group, []))  # type: ignore[attr-defined]


def _iter_entry_points() -> list[Any]:
    return _iter_group_entry_points("po.deployments")


def iter_formula_entry_points() -> list[Any]:
    """Return all registered `po.formulas` entry points."""
    return _iter_group_entry_points("po.formulas")


def load_formula_flows(
    *, skip_names: set[str] | frozenset[str] | None = None
) -> tuple[dict[str, Any], list[LoadError]]:
    """Load `po.formulas` callables keyed by entry-point name.

    Returns `(flows_by_name, errors)`. A formula pack that fails to load is
    reported as an error but does not abort the rest.
    """
    flows: dict[str, Any] = {}
    errors: list[LoadError] = []
    skipped = skip_names or set()
    for ep in iter_formula_entry_points():
        if ep.name in skipped:
            continue
        try:
            flows[ep.name] = ep.load()
        except Exception as exc:
            errors.append(LoadError(pack=ep.name, error=f"load failed: {exc}"))
    return flows, errors


def build_cron_deployments_from_order_dir(
    orders_dir: Path,
    *,
    tag_prefix: str,
    default_timezone: str = "UTC",
    work_pool_name: str = "po",
    log: logging.Logger | None = None,
) -> list[Any]:
    """Build Prefect cron deployments from flat TOML files in `orders_dir`.

    Schema:
      cron = "<cron expr>"           # required
      formula = "<po.formulas EP>"   # required
      description = "..."            # optional
      tags = ["a", "b"]              # optional; default: [tag_prefix, <formula>]
      timezone = "UTC"               # optional; default: `default_timezone`
      [params]                       # optional table -> parameters=
      key = value
    """
    active_logger = log or logger
    try:
        from prefect.client.schemas.schedules import CronSchedule
        from prefect.deployments.runner import EntrypointType
    except Exception as exc:  # pragma: no cover - prefect missing == bigger problem
        active_logger.warning("prefect unavailable; skipping deployments (%s)", exc)
        return []

    flows_by_name, load_errors = load_formula_flows()
    for err in load_errors:
        active_logger.warning("failed to load formula %r: %s", err.pack, err.error)

    deployments: list[Any] = []
    for toml_path in sorted(orders_dir.glob("*.toml")):
        try:
            with toml_path.open("rb") as fh:
                spec = tomllib.load(fh)
        except Exception as exc:
            active_logger.warning("failed to parse %s: %s", toml_path.name, exc)
            continue
        cron = spec.get("cron")
        formula_name = spec.get("formula")
        if not cron or not formula_name:
            active_logger.warning(
                "%s missing required keys (cron, formula); skipping", toml_path.name
            )
            continue
        flow_obj = flows_by_name.get(formula_name)
        if flow_obj is None:
            active_logger.warning(
                "formula %r referenced by %s is not registered; skipping",
                formula_name,
                toml_path.name,
            )
            continue
        params = spec.get("params") or {}
        if not isinstance(params, dict):
            active_logger.warning(
                "%s [params] must be a table; got %r",
                toml_path.name,
                type(params).__name__,
            )
            continue
        to_deployment = getattr(flow_obj, "to_deployment", None)
        if not callable(to_deployment):
            active_logger.warning(
                "formula %r referenced by %s is not a Prefect flow; skipping",
                formula_name,
                toml_path.name,
            )
            continue
        try:
            deployments.append(
                to_deployment(
                    name=toml_path.stem,
                    schedule=CronSchedule(
                        cron=cron, timezone=spec.get("timezone", default_timezone)
                    ),
                    tags=spec.get("tags", [tag_prefix, formula_name]),
                    description=spec.get(
                        "description",
                        f"{formula_name} cron deployment "
                        f"({cron} {spec.get('timezone', default_timezone)})",
                    ),
                    parameters=params,
                    work_pool_name=work_pool_name,
                    entrypoint_type=EntrypointType.MODULE_PATH,
                )
            )
        except Exception as exc:
            active_logger.warning("to_deployment failed for %s: %s", toml_path.name, exc)
            continue
    return deployments


def load_deployments() -> tuple[list[LoadedDeployment], list[LoadError]]:
    """Discover every registered deployment.

    Returns (loaded, errors). A pack that raises during `register()` is
    reported as an error but does not abort the rest.
    """
    loaded: list[LoadedDeployment] = []
    errors: list[LoadError] = []
    for ep in _iter_entry_points():
        try:
            register_fn = ep.load()
        except Exception as exc:
            errors.append(LoadError(pack=ep.name, error=f"load failed: {exc}"))
            continue
        if not callable(register_fn):
            errors.append(
                LoadError(
                    pack=ep.name, error=f"entry point is not callable: {register_fn!r}"
                )
            )
            continue
        try:
            result = register_fn()
        except Exception as exc:
            errors.append(LoadError(pack=ep.name, error=f"register() raised: {exc}"))
            continue
        # Normalize single-vs-list. Accept any iterable of deployments.
        if result is None:
            continue
        if isinstance(result, (list, tuple)):
            items = list(result)
        else:
            items = [result]
        for dep in items:
            loaded.append(LoadedDeployment(pack=ep.name, deployment=dep))
    return loaded, errors


def format_schedule(deployment: Any) -> str:
    """Render a deployment's schedule in one line for the listing.

    Handles Prefect 3 `RunnerDeployment` (`.schedules: list[DeploymentScheduleCreate]`),
    each wrapping a `CronSchedule`, `IntervalSchedule`, or `RRuleSchedule`.
    """
    schedules = getattr(deployment, "schedules", None) or []
    if not schedules:
        # Prefect 2 fallback
        single = getattr(deployment, "schedule", None)
        if single is None:
            return "manual"
        schedules = [single]
    parts: list[str] = []
    for entry in schedules:
        sched = getattr(entry, "schedule", entry)
        cls = type(sched).__name__
        if cls == "CronSchedule":
            tz = getattr(sched, "timezone", None)
            tz_str = f" {tz}" if tz else ""
            parts.append(f"cron({sched.cron}{tz_str})")
        elif cls == "IntervalSchedule":
            interval = getattr(sched, "interval", None)
            parts.append(f"interval({interval})")
        elif cls == "RRuleSchedule":
            parts.append(f"rrule({getattr(sched, 'rrule', '?')})")
        else:
            parts.append(cls)
    return ", ".join(parts) if parts else "manual"


def apply_deployment(deployment: Any, work_pool: str | None = None) -> str:
    """Apply a single deployment to the configured Prefect server.

    `RunnerDeployment.apply()` upserts by (flow_name, name), so re-running is
    idempotent. Returns the deployment ID as a string.
    """
    if work_pool is not None:
        # Set before apply so the server records the pool.
        deployment.work_pool_name = work_pool
    deployment_id = deployment.apply()
    return str(deployment_id)


def prefect_api_configured() -> bool:
    """Best-effort check that a Prefect API target is set.

    `--apply` needs a reachable Prefect server. `PREFECT_API_URL` is the
    standard env var; if unset Prefect falls back to an ephemeral SQLite DB

"""Collect + render the forensic trail from any formula's run dir.

Pure helpers used by `po artifacts`. The run dir layout is:

    <rig>/.planning/<formula>/<issue>/
      triage.md
      plan.md
      critique-iter-N.md
      verification-report-iter-N.md
      decision-log.md
      lessons-learned.md
      verdicts/*.json

Iter files are sorted by integer N so `iter-10` comes after `iter-2`.
Missing files render as a header with `(missing)` — never abort.
"""

from __future__ import annotations

import json
import re
from dataclasses import dataclass
from pathlib import Path

ITER_RE = re.compile(r"iter-(\d+)\.md$")

FIXED_SECTIONS: tuple[str, ...] = ("triage.md", "plan.md")
TRAILING_SECTIONS: tuple[str, ...] = ("decision-log.md", "lessons-learned.md")


@dataclass(frozen=True)
class Section:
    """One chunk of the forensic dump — a header and a body."""

    label: str
    path: Path
    body: str


def _iter_n(name: str) -> int | None:
    m = ITER_RE.search(name)
    return int(m.group(1)) if m else None


def _iter_pairs(run_dir: Path) -> list[Path]:
    """critique-iter-N.md + verification-report-iter-N.md sorted by N, critique first."""
    critiques = {
        _iter_n(p.name): p
        for p in run_dir.glob("critique-iter-*.md")
        if _iter_n(p.name) is not None
    }
    verifies = {
        _iter_n(p.name): p
        for p in run_dir.glob("verification-report-iter-*.md")
        if _iter_n(p.name) is not None
    }
    ns = sorted(set(critiques) | set(verifies))
    out: list[Path] = []
    for n in ns:
        if n in critiques:
            out.append(critiques[n])
        if n in verifies:
            out.append(verifies[n])
    return out


def _read_or_missing(path: Path, run_dir: Path) -> Section:
    try:
        rel = path.relative_to(run_dir)
    except ValueError:
        rel = path
    label = str(rel)
    if not path.exists():
        return Section(label=label, path=path, body="(missing)")
    if path.suffix == ".json":
        try:
            data = json.loads(path.read_text())
            body = json.dumps(data, indent=2, sort_keys=True)
        except (OSError, json.JSONDecodeError):
            body = path.read_text(errors="replace")
    else:
        body = path.read_text(errors="replace")
    return Section(label=label, path=path, body=body)


def collect_sections(run_dir: Path, *, verdicts_only: bool = False) -> list[Section]:
    """Ordered list of sections to render.

    verdicts_only=True restricts to `verdicts/*.json` (alphabetical).
    """
    if verdicts_only:
        return _collect_verdicts(run_dir)

    sections: list[Section] = []
    for name in FIXED_SECTIONS:
        sections.append(_read_or_missing(run_dir / name, run_dir))
    for iter_path in _iter_pairs(run_dir):
        sections.append(_read_or_missing(iter_path, run_dir))
    for name in TRAILING_SECTIONS:
        sections.append(_read_or_missing(run_dir / name, run_dir))
    sections.extend(_collect_verdicts(run_dir))
    return sections


def _collect_verdicts(run_dir: Path) -> list[Section]:
    verdicts_dir = run_dir / "verdicts"
    if not verdicts_dir.is_dir():
        return []
    return [
        _read_or_missing(p, run_dir)
        for p in sorted(verdicts_dir.glob("*.json"), key=lambda p: p.name)
    ]


def render(sections: list[Section]) -> str:
    """Plain-ASCII rendering — no ANSI, safe to pipe to `less`."""
    chunks: list[str] = []
    for sec in sections:
        chunks.append(f"===== {sec.label} =====")
        body = sec.body
        chunks.append(body if body.endswith("\n") else body + "\n")
    return "\n".join(chunks)

"""Runnable example flows for pack authors to copy and adapt."""

from __future__ import annotations

from pathlib import Path
from typing import Any

from prefect import flow
from prefect_orchestration.agent_session import AgentSession, ClaudeCliBackend, StubBackend
from prefect_orchestration.role_sessions import RoleSessionStore

from po_example_formulas.state import ExampleState


def _session_store(rig_path: Path, role: str) -> RoleSessionStore:
    run_dir = rig_path / ".planning" / "po-formulas-examples" / f"{role}-heartbeat"
    return RoleSessionStore(
        seed_id=f"example-{role}-heartbeat",
        seed_run_dir=run_dir,
    )


def _pick_builder_work(
    messages: list[dict[str, Any]], ready: list[dict[str, Any]]
) -> tuple[str, dict[str, Any]] | None:
    if messages:
        return "mail", messages[0]
    if ready:
        return "ready", ready[0]
    return None


def _classify_message(message: dict[str, Any]) -> tuple[str, dict[str, Any]]:
    hint = str(message.get("route_hint") or "").strip()
    if hint:
        return hint, {}
    haystack = " ".join(
        str(message.get(key, "")) for key in ("subject", "body", "sender")
    ).lower()
    if any(word in haystack for word in ("bug", "fix", "error", "issue", "todo")):
        return "create_bead", {}
    if any(word in haystack for word in ("invoice", "billing", "payment")):
        return "dispatch_formula", {"target_formula": "invoice-reconcile"}
    if any(word in haystack for word in ("reply", "respond")):
        return "draft_reply", {}
    return "ignore", {}


def _message_id(message: dict[str, Any], fallback: str) -> str:
    return str(message.get("message_id") or fallback)


@flow(name="builder_heartbeat", flow_run_name="{role}-heartbeat", log_prints=True)
def builder_heartbeat(
    rig_path: str,
    role: str = "builder",
    dry_run: bool = False,
    model: str = "opus",
    effort: str | None = None,
) -> dict[str, Any]:
    """Role-specific standing order over a dummy rig's local state.

    The flow checks role mail plus the ready queue under `.po-example/`,
    resumes a stable AgentSession for the role, prompts it to make one
    bounded step, then records the turn in a rig-local JSONL log.
    """
    rig = Path(rig_path).expanduser().resolve()
    state = ExampleState(rig)
    state.ensure()
    messages = state.load_role_mail(role)
    ready = state.load_ready(role)
    picked = _pick_builder_work(messages, ready)
    if picked is None:
        return {"status": "idle", "role": role, "message_count": 0, "ready_count": 0}

    source, item = picked
    if source == "mail":
        remaining_mail = messages[1:]
        state.save_role_mail(role, remaining_mail)
        bead_id = str(item.get("bead_id") or item.get("id") or "mail-task")
        goal = str(item.get("subject") or item.get("goal") or "Process message")
    else:
        remaining_ready = ready[1:]
        state.save_ready(role, remaining_ready)
        bead_id = str(item.get("bead_id") or "ready-task")
        goal = str(item.get("goal") or item.get("title") or "Do queued work")

    prompt = (
        f"Heartbeat role: {role}\n"
        f"Source: {source}\n"
        f"Bead: {bead_id}\n"
        f"Goal: {goal}\n\n"
        "Take one bounded step and leave the repo in a better state."
    )
    state.last_prompt_path(role).parent.mkdir(parents=True, exist_ok=True)
    state.last_prompt_path(role).write_text(prompt)

    store = _session_store(rig, role)
    backend = StubBackend() if dry_run else ClaudeCliBackend()
    sess = AgentSession(
        role=role,
        repo_path=rig,
        backend=backend,
        session_id=store.get(role),
        model=model,
        effort=effort,
        issue_id=bead_id,
        overlay=False,
        skills=False,
    )
    output = sess.prompt(prompt)
    if sess.session_id:
        store.set(role, sess.session_id)

    state.append_jsonl(
        state.run_log_path("heartbeat-runs"),
        {
            "role": role,
            "source": source,
            "bead_id": bead_id,
            "goal": goal,
            "session_id": sess.session_id,
            "output": output,
        },
    )
    return {
        "status": "worked",
        "role": role,
        "source": source,
        "bead_id": bead_id,
        "session_id": sess.session_id,
        "output": output,
    }


@flow(name="triage_inbox", flow_run_name="{account}-triage", log_prints=True)
def triage_inbox(
    rig_path: str,
    account: str = "default",
    limit: int = 25,
    target_role: str = "builder",
) -> dict[str, Any]:
    """Route inbox items from `.po-example/inbox/<account>/untriaged/`.

    For the dummy rig we use JSON files as inbound messages. The flow
    classifies each message, writes its side effect (bead, draft, or
    dispatch record), archives the message into `triaged/`, and returns
    route counts.
    """
    rig = Path(rig_path).expanduser().resolve()
    state = ExampleState(rig)
    state.ensure()
    counts: dict[str, int] = {}
    processed = 0
    for path, message in state.list_untriaged(account, limit):
        route, extra = _classify_message(message)
        counts[route] = counts.get(route, 0) + 1
        message_key = path.stem
        msg_id = _message_id(message, message_key)

        if route == "create_bead":
            bead_id = str(message.get("bead_id") or f"inbox-{message_key}")
            bead = {
                "id": bead_id,
                "status": "open",
                "source_message_id": msg_id,
                "title": message.get("subject") or bead_id,
                "labels": message.get("labels", ["intake"]),
                "metadata": {
                    "target_role": message.get("target_role", target_role),
                    "follow_on_formula": message.get("follow_on_formula"),
                },
            }
            state.write_bead(bead_id, bead)
            ready = state.load_ready(str(bead["metadata"]["target_role"]))
            ready.append(
                {
                    "bead_id": bead_id,
                    "goal": message.get("goal") or message.get("subject") or bead_id,
                    "source_message_id": msg_id,
                }
            )
            state.save_ready(str(bead["metadata"]["target_role"]), ready)
        elif route == "draft_reply":
            draft_path = state.drafts_dir() / f"{msg_id}.md"
            draft_path.parent.mkdir(parents=True, exist_ok=True)
            draft_path.write_text(
                f"# Draft reply for {msg_id}\n\nReply to: {message.get('sender', 'unknown')}\n"
            )
        elif route == "dispatch_formula":
            state.append_jsonl(
                state.run_log_path("dispatches"),
                {
                    "source": "triage-inbox",
                    "message_id": msg_id,
                    "formula": extra.get("target_formula")
                    or message.get("target_formula")
                    or "follow-up",
                },
            )

        archived = dict(message)
        archived["route"] = route
        archived["processed_by"] = "triage-inbox"
        state.archive_triaged(account, path, archived)
        processed += 1

    return {"status": "ok", "account": account, "processed": processed, "counts": counts}


@flow(name="on_bd_close", flow_run_name="{bead_id}", log_prints=True)
def on_bd_close(
    rig_path: str,
    bead_id: str,
) -> dict[str, Any]:
    """Follow-on trigger for a closed bead in the dummy rig.

    Reads the bead record under `.po-example/beads/<id>.json`. If the
    bead is closed and names a `follow_on_formula`, the flow records a
    dispatch event to `.po-example/dispatches.jsonl`.
    """
    rig = Path(rig_path).expanduser().resolve()
    state = ExampleState(rig)
    state.ensure()
    bead = state.read_bead(bead_id)
    if bead is None:
        return {"status": "ignored", "reason": "missing-bead", "bead_id": bead_id}
    if bead.get("status") != "closed":
        return {"status": "ignored", "reason": "not-closed", "bead_id": bead_id}

    metadata = bead.get("metadata") or {}
    follow_on = metadata.get("follow_on_formula")
    if not follow_on:
        return {"status": "ignored", "reason": "no-follow-on", "bead_id": bead_id}

    payload = {
        "source": "on-bd-close",
        "bead_id": bead_id,
        "formula": follow_on,
        "labels": bead.get("labels", []),
    }
    state.append_jsonl(state.run_log_path("dispatches"), payload)
    return {"status": "triggered", "bead_id": bead_id, "formula": str(follow_on)}

