    complexity: str,
    is_docs_only: bool,
    has_ui: bool,
) -> Path:
    work_type = classify_work_type(
        complexity=complexity,
        is_docs_only=is_docs_only,
        has_ui=has_ui,
    )
    manifest_path = run_dir / ARTIFACT_MANIFEST
    payload = {
        "contract_version": 1,
        "work_type": work_type,
        "run_dir": str(run_dir),
        "locations": {
            "verdicts": VERDICTS_DIR,
            "review_artifacts": REVIEW_ARTIFACTS_DIR,
            "transcripts": TRANSCRIPTS_DIR,
        },
        "artifacts": [
            _artifact_entry(run_dir, spec) for spec in _artifact_specs(work_type)
        ],
    }
    manifest_path.write_text(json.dumps(payload, indent=2, sort_keys=True) + "\n")
    return manifest_path


def ensure_handoff_summary(
    run_dir: Path,
    *,
    issue_id: str,
    complexity: str,
    is_docs_only: bool,
    has_ui: bool,
) -> Path:
    summary_path = run_dir / REVIEW_SUMMARY
    if summary_path.exists():
        return summary_path
    summary_path.parent.mkdir(parents=True, exist_ok=True)
    work_type = classify_work_type(
        complexity=complexity,
        is_docs_only=is_docs_only,
        has_ui=has_ui,
    )
    summary_path.write_text(
        "\n".join(
            [
                "# Handoff Summary",
                "",
                f"- Issue: `{issue_id}`",
                f"- Work type: `{work_type}`",
                f"- Run dir: `{run_dir}`",
                f"- Manifest: `{run_dir / ARTIFACT_MANIFEST}`",
                "",
                "Open this summary first, then follow the manifest for the rest of the proof set.",
                "",
            ]
        )
    )
    return summary_path
